import type { ReactNode } from "react";

import { Header } from "@/widgets/header";
import { Footer } from "@/widgets/footer";

export default function HomeRouteLayout({ children }: { children: ReactNode }) {
  return (
    <div className="flex min-h-screen flex-col">
      <Header />
      <main className="flex-1">{children}</main>
      <Footer />
    </div>
  );
}

export {
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
} from "./accordion";

"use client";

import {
  BellIcon,
  CircleUserRound,
  InboxIcon,
  LifeBuoyIcon,
  LogOutIcon,
  ScrollTextIcon,
} from "lucide-react";
import { signOut, useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";
import type { FC } from "react";

import { APP_ROUTES } from "@/shared/config/app-routes";
import { cn } from "@/shared/lib/ui/cn";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/shared/ui/dropdown-menu";
import { NotificationBadge } from "@/shared/ui/shadcn/badge";
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
} from "@/shared/ui/shadcn/navigation-menu";
import { MobileMenu } from "./mobile-menu";

const ABOUT_LINKS = [
  { title: "About LuxFlow", href: APP_ROUTES.APP.ABOUT },
  { title: "Our Method", href: APP_ROUTES.SERVICES.DIRECT_SALE }, // Используем константу из роутов
  { title: "Contact Us", href: APP_ROUTES.APP.CONTACT },
  { title: "Support", href: APP_ROUTES.SUPPORT },
  { title: "FAQs", href: APP_ROUTES.APP.FAQ },
];

const NAV_LINKS = [
  { title: "Home", href: "/" },
  { title: "Buyback", href: "/services/buyback" },
  { title: "Permanent Sale", href: APP_ROUTES.SERVICES.DIRECT_SALE },
];

interface HeaderProps {
  className?: string;
}

export const Header: FC<HeaderProps> = ({ className }) => {
  const { status } = useSession();
  const isAuthenticated = status === "authenticated";
  const router = useRouter();

  const handleLogout = async () => {
    await signOut({ redirect: false });
    router.push(APP_ROUTES.AUTH.SIGN_IN);
    router.refresh();
  };

  const whatsappUrl = "https://wa.me/???";

  return (
    <header
      className={cn(
        "new-design w-full border-border border-b bg-background font-[500] font-new-sans text-sm",
        className,
      )}
    >
      <div className="mx-auto max-w-[1720px] px-4 py-3 min-[1172px]:px-10">
        <div className="hidden grid-cols-3 items-center lg:grid">
          <nav className="flex items-center gap-4 xl:gap-6">
            {NAV_LINKS.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className="whitespace-nowrap transition-opacity hover:opacity-60"
              >
                {link.title}
              </Link>
            ))}

            {isAuthenticated && (
              <Link
                href="/my-deals"
                className="whitespace-nowrap transition-opacity hover:opacity-60"
              >
                My Offers
              </Link>
            )}

            <NavigationMenu>
              <NavigationMenuList>
                <NavigationMenuItem>
                  <NavigationMenuTrigger className="h-auto p-0 font-[500] font-new-sans text-sm hover:bg-transparent hover:opacity-60 focus:bg-transparent">
                    About
                  </NavigationMenuTrigger>
                  <NavigationMenuContent>
                    <ul className="flex w-[200px] flex-col gap-1 rounded-md border border-border bg-background p-2">
                      {ABOUT_LINKS.map((link) => (
                        <li key={link.href}>
                          <NavigationMenuLink asChild>
                            <Link
                              href={link.href}
                              className="block rounded-sm px-3 py-2 font-normal text-sm transition-colors hover:bg-transparent hover:text-foreground"
                            >
                              {link.title}
                            </Link>
                          </NavigationMenuLink>
                        </li>
                      ))}
                    </ul>
                  </NavigationMenuContent>
                </NavigationMenuItem>
              </NavigationMenuList>
            </NavigationMenu>
          </nav>

          <div className="flex justify-center">
            <Logo className="h-8 w-48" />
          </div>

          <div className="flex items-center justify-end gap-3 xl:gap-5">
            <a
              href={whatsappUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-2 hover:opacity-60"
            >
              <span className="hidden xl:inline">Text Us</span>
              <Image
                src="/new-design-images/icons/whatsup.svg"
                alt="WhatsApp"
                width={20}
                height={20}
              />
            </a>

            <Link
              href={APP_ROUTES.BUYBACK_REQUESTS.CREATE}
              className="whitespace-nowrap rounded bg-[#000E65] px-4 py-2 font-medium text-[12px] text-white transition-colors hover:bg-blue-900"
            >
              Start with a Quote
            </Link>

            {isAuthenticated ? (
              <div className="flex items-center gap-4">
                <NotificationBadge className="cursor-pointer">
                  <BellIcon
                    size={24}
                    className="text-foreground"
                    aria-label="Notifications"
                  />
                </NotificationBadge>
                <div className="h-8 w-[1px] bg-[#D6D3D1]" />
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <button
                      type="button"
                      className="cursor-pointer overflow-hidden rounded-[4px] border border-transparent transition-colors hover:border-border focus:outline-none"
                      aria-label="User menu"
                    >
                      <Image
                        src="/new-design-images/avatar-example.png"
                        alt="User Profile"
                        width={36}
                        height={36}
                        className="object-cover"
                      />
                    </button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent
                    align="end"
                    sideOffset={8}
                    className="w-[220px] rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] p-1 shadow-[0px_4px_16px_rgba(0,0,0,0.08)]"
                  >
                    <DropdownMenuItem asChild>
                      <Link
                        href={APP_ROUTES.PROFILE}
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      >
                        <CircleUserRound
                          size={16}
                          className="shrink-0 text-[#44403C]"
                        />
                        Profile Settings
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        href={APP_ROUTES.WALLET.ROOT}
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      >
                        <InboxIcon
                          size={16}
                          className="shrink-0 text-[#44403C]"
                        />
                        Accounts & Wallets
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        href={APP_ROUTES.WALLET.PAYMENT_HISTORY}
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      >
                        <ScrollTextIcon
                          size={16}
                          className="shrink-0 text-[#44403C]"
                        />
                        Transaction History
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuSeparator className="my-1 bg-[#D6D3D1]" />
                    <DropdownMenuItem
                      onClick={handleLogout}
                      className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                    >
                      <LogOutIcon
                        size={16}
                        className="shrink-0 text-[#44403C]"
                      />
                      Logout
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  href={APP_ROUTES.AUTH.SIGN_IN}
                  className="hover:opacity-60"
                >
                  Login
                </Link>
                <div className="h-4 w-[1px] bg-black/10" />
                <Link
                  href={APP_ROUTES.AUTH.SIGN_UP}
                  className="hover:opacity-60"
                >
                  Register
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* --- Mobile Version --- */}
        <div className="flex items-center justify-between lg:hidden">
          <MobileMenu isAuthenticated={isAuthenticated} />

          <Logo className="h-6 w-32" />

          <div className="flex items-center gap-3">
            <a
              href={whatsappUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="hover:opacity-60"
              aria-label="Contact on WhatsApp"
            >
              <Image
                src="/new-design-images/icons/whatsup.svg"
                alt=""
                width={22}
                height={22}
              />
            </a>
            {isAuthenticated ? (
              <NotificationBadge>
                <BellIcon size={22} aria-label="Notifications" />
              </NotificationBadge>
            ) : (
              <Link href={APP_ROUTES.AUTH.SIGN_IN} className="text-md">
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

const Logo = ({ className }: { className: string }) => (
  <Link href="/" className={cn("relative", className)}>
    <Image
      src="/new-design-images/header-logo.svg"
      alt="LUXFLOW"
      fill
      className="object-contain"
      priority
    />
  </Link>
);

