@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  /* Old design (without class .new-design) */
  :root {
    --background: 0 0% 100%;
    --foreground: 0 0% 0%;

    --card: 0 0% 100%;
    --card-foreground: 0 0% 0%;

    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 0%;

    --primary: 174 100% 23.7%;
    --primary-foreground: 0 0% 100%;

    --secondary: 200 8% 80%;
    --secondary-foreground: 0 0% 0%;

    --muted: 200 8% 80%;
    --muted-foreground: 0 7% 72.5%;

    --accent: 200 8% 80%;
    --accent-foreground: 0 0% 0%;

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 100%;

    --border: 200 8% 80%;
    --input: 200 8% 80%;
    --ring: 174 100% 23.7%;
    --radius: 0.625rem;

    --font-serif: "Inria Serif", serif;
    --font-sans: "Inter", sans-serif;
  }

  .dark {
    --background: 222.2 84% 4.9%;
    --foreground: 210 40% 98%;

    --card: 222.2 84% 4.9%;
    --card-foreground: 210 40% 98%;

    --popover: 222.2 84% 4.9%;
    --popover-foreground: 210 40% 98%;

    --primary: 217.2 91.2% 59.8%;
    --primary-foreground: 222.2 47.4% 11.2%;

    --secondary: 217.2 32.6% 17.5%;
    --secondary-foreground: 210 40% 98%;

    --muted: 217.2 32.6% 17.5%;
    --muted-foreground: 215 20.2% 65.1%;

    --accent: 217.2 32.6% 17.5%;
    --accent-foreground: 210 40% 98%;

    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;

    --border: 217.2 32.6% 17.5%;
    --input: 217.2 32.6% 17.5%;
    --ring: 224.3 76.3% 48%;
  }

  /* New design (add class .new-design) */
  .new-design {
    /* Backgrounds */
    --background: 40 22% 95%; /*  #F5F3EF */
    --foreground: 30 6% 25%; /*  #443F3C */
    --card: 40 22% 95%;
    --card-foreground: 228 60% 7%;

    --popover: 0 0% 100%;
    --popover-foreground: 228 60% 7%;

    /* Primary - Blue */
    --primary: 232 95% 23%; /* #021171 */
    --primary-foreground: 0 0% 100%;

    /* Secondary - Platinum / Isabelline */
    --secondary: 40 16% 91%; /* Platinum #E6E2DC */
    --secondary-foreground: 228 60% 7%;

    /* Destructive  */
    --destructive: 0 84% 41%;
    --destructive-foreground: 0 0% 100%;

    /* Outline and icons*/
    --outline-gray: 24 5% 65%;

    /* Muted */
    --muted: 40 16% 91%;
    --muted-foreground: 228 10% 40%;

