"use client";

import * as AccordionPrimitive from "@radix-ui/react-accordion";
import { ChevronDownOutline } from "react-ionicons";
import type { ComponentProps } from "react";

import { cn } from "../../lib/ui/cn";

function Accordion({
  ...props
}: ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />;
}

function AccordionItem({
  className,
  ...props
}: ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn(
        "border-[#D0D5DB] border-b pt-[10px] pb-[10px] first:pt-0",
        className,
      )}
      {...props}
    />
  );
}

function AccordionTrigger({
  className,
  children,
  ...props
}: ComponentProps<typeof AccordionPrimitive.Trigger>) {
  return (
    <AccordionPrimitive.Header className="flex">
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cn(
          "flex w-full items-center gap-[15px] px-5 py-2.5 text-left outline-none transition-colors hover:bg-secondary/20 focus-visible:bg-secondary/20 disabled:pointer-events-none disabled:opacity-50 [&[data-state=open]>svg]:rotate-180",
          className,
        )}
        {...props}
      >
        <ChevronDownOutline
          width="24px"
          height="24px"
          color="#1D1B20"
          className="shrink-0 transition-transform duration-200"
        />
        <span className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
          {children}
        </span>
      </AccordionPrimitive.Trigger>
    </AccordionPrimitive.Header>
  );
}

function AccordionContent({
  className,
  children,
  ...props
}: ComponentProps<typeof AccordionPrimitive.Content>) {
  return (
    <AccordionPrimitive.Content
      data-slot="accordion-content"
      className="overflow-hidden transition-all data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down"
      {...props}
    >
      <div className={cn("px-5 py-2", className)}>
        <div className="font-serif text-base text-foreground leading-[1.199em]">
          {children}
        </div>
      </div>
    </AccordionPrimitive.Content>
  );
}

export { Accordion, AccordionItem, AccordionTrigger, AccordionContent };

