"use client";

import {
  type Variants,
  motion,
  useScroll,
  useTransform,
} from "framer-motion";
import { CheckIcon } from "lucide-react";
import { useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { useRef } from "react";

import { useRole } from "@/entities/auth/model/use-role";
import { APP_ROUTES } from "@/shared/config/app-routes";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/shared/ui/accordion";

import {
  LANDING_AUTH_FEATURES,
  LANDING_BRAND_LOGOS,
  LANDING_FAQ,
  LANDING_STEPS,
  LANDING_TRUST_FEATURES,
  LANDING_VALUE_PROPS,
} from "../model/constants";

// ---------------------------------------------------------------------------
// Animation variants
// ---------------------------------------------------------------------------
const fadeUp: Variants = {
  hidden: { opacity: 0, y: 48 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
  },
};

const fadeIn: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { duration: 0.6, ease: "easeOut" },
  },
};

const slideLeft: Variants = {
  hidden: { opacity: 0, x: -60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const slideRight: Variants = {
  hidden: { opacity: 0, x: 60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const scaleIn: Variants = {
  hidden: { opacity: 0, scale: 0.88 },
  visible: {
    opacity: 1,
    scale: 1,
    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },
  },
};

const staggerContainer: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.1 } },
};

const staggerContainerSlow: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.15 } },
};

// viewport settings shared across all whileInView
const VP = { once: true, margin: "-80px" };

// ---------------------------------------------------------------------------
// Image placeholder — remove and replace with <Image> once assets are provided
// ---------------------------------------------------------------------------
function ImgPlaceholder({
  name,
  className,
}: {
  name: string;
  className?: string;
}) {
  return (
    <div
      className={`flex items-center justify-center bg-[#C8C0B0] text-center text-[10px] text-[#8A8070] ${className ?? ""}`}
    >
      <span className="px-2">{name}</span>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Hero headline — word-by-word reveal
// ---------------------------------------------------------------------------
function AnimatedHeadline({
  text,
  className,
}: {
  text: string;
  className?: string;
}) {
  const words = text.split(" ");
  return (
    <motion.h1
      className={className}
      variants={staggerContainer}
      initial="hidden"
      animate="visible"
    >
      {words.map((word, idx) => (
        <motion.span
          // eslint-disable-next-line react/no-array-index-key
          key={`word-${idx}`}
          className="inline-block"
          variants={{
            hidden: { opacity: 0, y: 40, rotateX: -15 },
            visible: {
              opacity: 1,
              y: 0,
              rotateX: 0,
              transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
            },
          }}
        >
          {word}
          {idx < words.length - 1 ? "\u00A0" : ""}
        </motion.span>
      ))}
    </motion.h1>
  );
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------
export function LandingPage() {
  const { status } = useSession();
  const { isSeller } = useRole();
  const isAuthenticated = status === "authenticated";

  const ctaHref =
    isAuthenticated && !isSeller
      ? undefined
      : isAuthenticated
        ? APP_ROUTES.BUYBACK_REQUESTS.CREATE
        : `${APP_ROUTES.AUTH.SIGN_IN}?callbackUrl=${encodeURIComponent(APP_ROUTES.BUYBACK_REQUESTS.CREATE)}`;

  // Parallax for hero background
  const heroRef = useRef<HTMLElement>(null);
  const { scrollYProgress: heroScrollY } = useScroll({
    target: heroRef,
    offset: ["start start", "end start"],
  });
  const heroBgY = useTransform(heroScrollY, [0, 1], ["0%", "30%"]);

  return (
    <div className="new-design flex flex-col">
      {/* ================================================================
          1. HERO
      ================================================================ */}
      <section
        ref={heroRef}
        className="relative overflow-hidden bg-[#060B2F] px-6 pb-16 pt-20 min-[1172px]:px-16 min-[1172px]:pb-32 min-[1172px]:pt-36"
      >
        {/* Parallax background */}
        {/* Asset name: landing-hero-bg — blurred luxury watch background image */}
        <motion.div
          className="pointer-events-none absolute inset-0 opacity-20"
          style={{ y: heroBgY }}
        >
          <ImgPlaceholder
            name="landing-hero-bg (blurred watch background image)"
            className="h-full w-full"
          />
        </motion.div>

        <div className="relative mx-auto max-w-[1720px]">
          <div className="flex flex-col gap-10 min-[1172px]:flex-row min-[1172px]:items-end min-[1172px]:justify-between">
            <div className="flex max-w-2xl flex-col gap-6">
              {/* Word-by-word reveal */}
              <AnimatedHeadline
                text="Unlock instant liquidity"
                className="font-extralight font-new-serif text-5xl leading-[1.05] tracking-tight text-white [perspective:600px] min-[1172px]:text-[72px]"
              />

              <motion.p
                className="font-new-sans text-base text-white/70 min-[1172px]:text-lg"
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.5 }}
              >
                LuxFlow combines speed, security, and sophistication. With
                Brink&apos;s handling item custody and a multi-layered
                authentication process that combines AI and trusted experts.
              </motion.p>

              <motion.div
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.7 }}
              >
                {ctaHref ? (
                  <motion.div
                    whileHover={{ scale: 1.03 }}
                    whileTap={{ scale: 0.97 }}
                    className="w-fit"
                  >
                    <Link
                      href={ctaHref}
                      className="inline-flex h-12 items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-[#000E65]"
                    >
                      Unlock Your Liquidity
                    </Link>
                  </motion.div>
                ) : (
                  <button
                    type="button"
                    disabled
                    className="inline-flex h-12 w-fit items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white opacity-50"
                  >
                    Unlock Your Liquidity
                  </button>
                )}
              </motion.div>
            </div>

            <motion.div
              className="flex flex-col items-start gap-1 text-white/50 min-[1172px]:items-end"
              variants={fadeIn}
              initial="hidden"
              animate="visible"
              transition={{ delay: 0.4 }}
            >
              <span className="font-new-sans text-sm">
                from your luxury items
              </span>
            </motion.div>
          </div>

          {/* Hero watch image — slides in from right */}
          {/* Asset name: landing-hero-watch — product photo of a luxury watch */}
          <motion.div
            className="pointer-events-none absolute right-0 top-1/2 hidden -translate-y-1/2 min-[1172px]:block"
            variants={slideRight}
            initial="hidden"
            animate="visible"
            transition={{ delay: 0.3 }}
          >
            <ImgPlaceholder
              name="landing-hero-watch (luxury watch product photo)"
              className="h-[380px] w-[340px] rounded-2xl"
            />
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          2. VALUE PROPOSITIONS
      ================================================================ */}
      <section className="bg-[#1236A8] px-6 py-14 min-[1172px]:px-16 min-[1172px]:py-20">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-12">
          <motion.p
            className="mx-auto max-w-2xl text-center font-new-sans text-base leading-relaxed text-white/80 min-[1172px]:text-lg"
            variants={fadeUp}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            LuxFlow combines speed, security, and sophistication. With
            Brink&apos;s handling item custody and a multi-layered
            authentication process that combines AI and trusted experts.
          </motion.p>

          <motion.div
            className="grid grid-cols-2 gap-4 min-[1172px]:grid-cols-4 min-[1172px]:gap-6"
            variants={staggerContainer}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {LANDING_VALUE_PROPS.map((prop) => (
              <motion.div
                key={prop.id}
                variants={scaleIn}
                whileHover={{ scale: 1.04, backgroundColor: "rgba(255,255,255,0.18)" }}
                className="flex flex-col items-center gap-4 rounded-2xl bg-white/10 px-4 py-6 text-center backdrop-blur-sm transition-colors"
              >
                {/* Asset name: landing-icon-{prop.id} — small icon SVG for value prop */}
                <div className="flex h-12 w-12 items-center justify-center rounded-full bg-white/20">
                  <ImgPlaceholder
                    name={`landing-icon-${prop.id}`}
                    className="h-6 w-6 rounded"
                  />
                </div>
                <span className="font-medium font-new-sans text-sm text-white">
                  {prop.label}
                </span>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          3. GALLERY — "Liquid Luxury"
      ================================================================ */}
      <section className="bg-[#1236A8] px-6 pb-20 min-[1172px]:px-16">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-10">
          {/* Staggered gallery images */}
          {/* Asset names: landing-gallery-bags, landing-gallery-gold, landing-gallery-jewelry */}
          <motion.div
            className="grid grid-cols-1 gap-3 min-[768px]:grid-cols-3"
            variants={staggerContainer}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {(
              [
                "landing-gallery-bags (designer bags & accessories)",
                "landing-gallery-gold (gold watches & precious metals)",
                "landing-gallery-jewelry (fine jewelry & diamonds)",
              ] as const
            ).map((name, idx) => (
              <motion.div
                // eslint-disable-next-line react/no-array-index-key
                key={idx}
                variants={fadeUp}
                className="overflow-hidden rounded-2xl"
                whileHover={{ scale: 1.02 }}
                transition={{ type: "spring", stiffness: 200, damping: 20 }}
              >
                <ImgPlaceholder
                  name={name}
                  className="h-[260px] w-full min-[1172px]:h-[340px]"
                />
              </motion.div>
            ))}
          </motion.div>

          <div className="flex flex-col items-start gap-6 min-[1172px]:flex-row min-[1172px]:items-end min-[1172px]:justify-between">
            <motion.h2
              className="font-extralight font-new-serif text-4xl leading-[1.1] tracking-tight text-white min-[1172px]:text-[56px]"
              variants={fadeUp}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              Liquid Luxury
              <br />
              Fast. Discreet. Hassle-free.
            </motion.h2>

            {ctaHref ? (
              <motion.div
                variants={fadeIn}
                initial="hidden"
                whileInView="visible"
                viewport={VP}
                whileHover={{ scale: 1.03 }}
                whileTap={{ scale: 0.97 }}
                className="shrink-0"
              >
                <Link
                  href={ctaHref}
                  className="inline-flex h-12 items-center rounded-lg border border-white/30 bg-white/10 px-8 font-medium font-new-sans text-base text-white backdrop-blur-sm transition-colors hover:bg-white/20"
                >
                  Start with a Quote
                </Link>
              </motion.div>
            ) : null}
          </div>
        </div>
      </section>

      {/* ================================================================
          4. BUYBACK OPTIONS — two columns
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-16 min-[1172px]:px-16 min-[1172px]:py-24">
        <div className="mx-auto max-w-[1720px] grid grid-cols-1 gap-12 min-[1172px]:grid-cols-2 min-[1172px]:gap-16">
          {/* Left — slides from left */}
          <motion.div
            className="flex flex-col gap-6"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {/* Asset name: landing-buyback-option-watch — close-up watch on dark surface */}
            <motion.div
              className="overflow-hidden rounded-2xl"
              whileHover={{ scale: 1.02 }}
              transition={{ type: "spring", stiffness: 200, damping: 20 }}
            >
              <ImgPlaceholder
                name="landing-buyback-option-watch (close-up luxury watch photo)"
                className="h-[280px] min-[1172px]:h-[320px]"
              />
            </motion.div>
            <div className="flex flex-col gap-3">
              <h3 className="font-extralight font-new-serif text-2xl leading-[1.2] text-[#44403C] min-[1172px]:text-3xl">
                Keep the option to
                <br />
                buy back your item
              </h3>
              <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                LuxFlow offers a flexible buyback option. Reclaim your luxury
                asset at the agreed price — no questions asked.
              </p>
              <Link
                href={APP_ROUTES.SERVICES.BUYBACK}
                className="font-medium font-new-sans text-sm text-[#021171] underline-offset-2 hover:underline"
              >
                Learn More
              </Link>
            </div>
          </motion.div>

          {/* Right — slides from right */}
          <motion.div
            className="flex flex-col gap-6"
            variants={slideRight}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {/* Asset name: landing-capital-option-watch — gold Rolex Daytona style watch */}
            <motion.div
              className="overflow-hidden rounded-2xl"
              whileHover={{ scale: 1.02 }}
              transition={{ type: "spring", stiffness: 200, damping: 20 }}
            >
              <ImgPlaceholder
                name="landing-capital-option-watch (gold Rolex Daytona style watch photo)"
                className="h-[280px] min-[1172px]:h-[320px]"
              />
            </motion.div>
            <div className="flex flex-col gap-3">
              <h3 className="font-extralight font-new-serif text-2xl leading-[1.2] text-[#44403C] min-[1172px]:text-3xl">
                Convert your items
                <br />
                into capital
              </h3>
              <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                Turn idle luxury assets into working capital instantly. LuxFlow
                connects you to a secure, fast, and discreet liquidity service.
              </p>
              <Link
                href={APP_ROUTES.SERVICES.DIRECT_SALE}
                className="font-medium font-new-sans text-sm text-[#021171] underline-offset-2 hover:underline"
              >
                Learn More
              </Link>
            </div>
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          5. STEPS — "Get Instant Cash in 4 Simple Steps"
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-16 min-[1172px]:px-16 min-[1172px]:py-24">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-12 min-[1172px]:flex-row min-[1172px]:items-start min-[1172px]:gap-20">
          {/* Phone mockup — slides in from left */}
          {/* Asset name: landing-app-mockup — iPhone mockup showing LuxFlow app UI */}
          <motion.div
            className="flex justify-center min-[1172px]:w-[380px] min-[1172px]:shrink-0 min-[1172px]:justify-start"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <ImgPlaceholder
              name="landing-app-mockup (iPhone showing LuxFlow app UI)"
              className="h-[500px] w-[240px] rounded-[32px] min-[1172px]:h-[580px] min-[1172px]:w-[280px]"
            />
          </motion.div>

          {/* Steps — staggered reveal */}
          <div className="flex flex-1 flex-col gap-8">
            <motion.h2
              className="font-extralight font-new-serif text-3xl leading-[1.2] text-[#44403C] min-[1172px]:text-[44px]"
              variants={fadeUp}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              Get Instant Cash
              <br />
              in 4 Simple Steps
            </motion.h2>

            <motion.div
              className="flex flex-col gap-6"
              variants={staggerContainerSlow}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
