import type {
  AssetHandoverOption,
  AssetHandoverStatus,
  AssetHandoverType,
} from "@/shared/types";
import type {
  BuybackListItem,
  BuybackStatus,
  BuybackType,
} from "./buyback.types";

export enum BuybackRequestStatus {
  // Quote
  New = "NEW",
  PendingValuation = "PENDING_VALUATION",
  ValuationReceived = "VALUATION_RECEIVED",

  // Pre-auth
  PreAuthOfferSent = "OFFER_SENT",
  PreAuthOfferAccepted = "OFFER_ACCEPTED",

  // Post-auth
  AssetReceived = "ASSET_RECEIVED",
  PendingAuth = "PENDING_AUTH",
  AuthCompleted = "AUTH_COMPLETED",

  // Entrupy verification (optional step after AuthCompleted)
  PendingEntrupy = "PENDING_ENTRUPY",

  // Final offer
  FinalOfferSent = "FINAL_OFFER_SENT",
  KycApproved = "KYC_APPROVED",
  KycPending = "KYC_PENDING",

  // Offer accepted
  FinalOfferAccepted = "FINAL_OFFER_ACCEPTED",

  // Rejected (by admin)
  PreAuthVerificationFailed = "PRE_AUTH_VERIFICATION_FAILED",
  PostAuthVerificationFailed = "POST_AUTH_VERIFICATION_FAILED",
  KYCFailed = "KYC_FAILED",

  // Rejected (by user)
  RejectedPreAuthOffer = "REJECTED_PRE_AUTH_OFFER",
  RejectedPostAuthOffer = "REJECTED_POST_AUTH_OFFER",
}

export enum BuybackRequestStage {
  Quote = "QUOTE",
  PreAuth = "PRE_AUTH",
  PostAuth = "POST_AUTH",
  FinalOffer = "FINAL_OFFER",
  Rejected = "REJECTED",

  // went through the entire flow
  OfferAccepted = "OfferAccepted",
}

export enum BuybackOfferType {
  PreAuth = "PRE_AUTH",
  PostAuth = "POST_AUTH",
}

export interface BuybackRequestEvent {
  status: BuybackRequestStatus;
  stage: BuybackRequestStage;
  timestamp: Date | string;
}

export interface OfferData {
  amountCents: number;
  serviceFeeCents: number;
  serviceFeePercentage: number;
  authenticationFeeCents: number;
  custodyFeeCents: number;
  platformFeeCents: number;
  insuranceFeeCents: number;
  vatCents: number;
  toBeReceivedCents: number;
}

export interface BuybackOffer {
  id: string;
  type: BuybackOfferType;
  data: OfferData;
  createdAt: Date | string;
  updatedAt: Date | string;
}

export interface AssetMeta {
  photos?: {
    order: string[];
    main: string;
  } | null;
  authPhotos?: {
    order: string[];
    main: string;
  } | null;
}

export interface AssetHandover {
  id: string;
  type: AssetHandoverType;
  status: AssetHandoverStatus;
  option: AssetHandoverOption;
  courierNumber: string | null;
  visitDate: Date | string | null;
  courierPartner: {
    id: string;
    name: string;
  } | null;
  toCustodyLocation: {
    id: string;
    name: string;
    custody: {
      id: string;
      name: string;
    } | null;
  } | null;
  fromCustodyLocation: {
    id: string;
    name: string;
    custody: {
      id: string;
      name: string;
    } | null;
  } | null;
}

export interface BuybackRequestListItem {
  id: string;
  status: BuybackRequestStatus;
  stage: BuybackRequestStage;
  createdAt: Date | string;
  buyback: Omit<BuybackListItem, "createdAt">;
}

export enum BuybackExtensionType {
  Default = "DEFAULT",
  Automatic = "AUTOMATIC",
  Manual = "MANUAL",
}

export interface BuybackComputedDetails {
  outstandingAmountCents: number;
  tenure: number;
  receivedAmountCents: number;
  fundedOn: string;
  approvedOn: string;
  dueDate: string;
  purchasePriceCents: number;
  serviceFeeCents: number;
  serviceFeePercentage: number;
}

export interface BuybackExtension {
  id: string;
  buybackId: string;
  type: BuybackExtensionType;
  month: number;
  startDate: string;
  endDate: string;
}

export interface BuybackRequestDetail {
  id: string;
  status: BuybackRequestStatus;
  stage: BuybackRequestStage;
  createdAt: Date | string;
  rejectReason?: string;
  entrupyRequired: boolean;
  entrupySkipped: boolean;
  entrupySkippedReason: string | null;
  entrupySkippedById: string | null;
  seller: {
    id: string;
    fullName: string;
    email: string;
    phone?: string;
    status?: string;
    kycStatus?: string;
    kyc?: {
      status: string;
    };
  };
  buyback: {
    id: string;
    type: BuybackType;
    status: BuybackStatus;
    computedDetails?: BuybackComputedDetails;
    extensions?: BuybackExtension[];
    asset: {
      id: string;
      category: { id: string; name: string };
      brand: { id: string; name: string };
      model: { id: string; name: string };
      year?: number;
      condition?: string;
      modelNumber?: string;
      categoryFields?: Record<string, string>;
      meta: AssetMeta;
      photos: string[];
      authPhotos?: string[];
      declarationFormId: string | null;
      podId: string | null;
      openBoxVideoId: string | null;
      handover: AssetHandover | null;
    };
  };
  preAuthOffer?: BuybackOffer;
  postAuthOffer?: BuybackOffer;
  eventsLog: BuybackRequestEvent[];
}

export interface BuybackRequestsResponse {
  total: number;
  skip: number;
  take: number;
  data: BuybackRequestListItem[];
}

export interface BuybackRequestFilters {
  skip?: number;
  take?: number;
  order?: "ASC" | "DESC";
  search?: string;
  categories?: string[];
  brands?: string[];
  types?: BuybackType[];
  statuses?: BuybackRequestStatus[];
}

export interface AcceptPreAuthOfferRequest {
  declarationFormId: string;
  assetHandoverOption: AssetHandoverOption;
  custodyLocationId: string;
  courierPartnerId?: string;
  courierNumber?: string;
  visitDate?: Date | string;
}

export interface RejectOfferRequest {
  reason: string;
}

export const BB_REQUEST_STATUS_TO_STAGE: Record<
  BuybackRequestStatus,
  BuybackRequestStage
> = {
  [BuybackRequestStatus.New]: BuybackRequestStage.Quote,
  [BuybackRequestStatus.PendingValuation]: BuybackRequestStage.Quote,
  [BuybackRequestStatus.ValuationReceived]: BuybackRequestStage.Quote,
  [BuybackRequestStatus.PreAuthOfferSent]: BuybackRequestStage.PreAuth,
  [BuybackRequestStatus.PreAuthOfferAccepted]: BuybackRequestStage.PreAuth,
  [BuybackRequestStatus.AssetReceived]: BuybackRequestStage.PostAuth,
  [BuybackRequestStatus.PendingAuth]: BuybackRequestStage.PostAuth,
  [BuybackRequestStatus.AuthCompleted]: BuybackRequestStage.PostAuth,
  [BuybackRequestStatus.PendingEntrupy]: BuybackRequestStage.PostAuth,
  [BuybackRequestStatus.FinalOfferSent]: BuybackRequestStage.FinalOffer,
  [BuybackRequestStatus.KycApproved]: BuybackRequestStage.FinalOffer,
  [BuybackRequestStatus.KycPending]: BuybackRequestStage.FinalOffer,
  [BuybackRequestStatus.FinalOfferAccepted]: BuybackRequestStage.OfferAccepted,
  [BuybackRequestStatus.PreAuthVerificationFailed]:
    BuybackRequestStage.Rejected,
  [BuybackRequestStatus.PostAuthVerificationFailed]:
    BuybackRequestStage.Rejected,
  [BuybackRequestStatus.KYCFailed]: BuybackRequestStage.Rejected,
  [BuybackRequestStatus.RejectedPreAuthOffer]: BuybackRequestStage.Rejected,
  [BuybackRequestStatus.RejectedPostAuthOffer]: BuybackRequestStage.Rejected,
};

export const getStatusLabel = (status: BuybackRequestStatus): string => {
  const statusLabels: Record<BuybackRequestStatus, string> = {
    [BuybackRequestStatus.New]: "Request",
    [BuybackRequestStatus.PendingValuation]: "Pending Valuation",
    [BuybackRequestStatus.ValuationReceived]: "Valuation Received",
    [BuybackRequestStatus.PreAuthOfferSent]: "Offer Sent",
    [BuybackRequestStatus.PreAuthOfferAccepted]: "Offer Accepted",
    [BuybackRequestStatus.AssetReceived]: "Asset Received",
    [BuybackRequestStatus.PendingAuth]: "Pending Authentication",
    [BuybackRequestStatus.AuthCompleted]: "Authentication Completed",
    [BuybackRequestStatus.PendingEntrupy]: "Pending Entrupy Verification",
    [BuybackRequestStatus.FinalOfferSent]: "Final Offer Sent",
    [BuybackRequestStatus.KycApproved]: "KYC Approved",
    [BuybackRequestStatus.KycPending]: "KYC Pending",
    [BuybackRequestStatus.FinalOfferAccepted]: "Offer Accepted",
    [BuybackRequestStatus.PreAuthVerificationFailed]:
      "Pre-Auth Verification Failed",
    [BuybackRequestStatus.PostAuthVerificationFailed]:
      "Post-Auth Verification Failed",
    [BuybackRequestStatus.KYCFailed]: "KYC Failed",
    [BuybackRequestStatus.RejectedPreAuthOffer]: "Pre-Auth Offer Rejected",
    [BuybackRequestStatus.RejectedPostAuthOffer]: "Post-Auth Offer Rejected",
  };
  return statusLabels[status] || status;
};

export const getStageColor = (stage: BuybackRequestStage): string => {
  const stageColors: Record<BuybackRequestStage, string> = {
    [BuybackRequestStage.Quote]: "text-blue-600",
    [BuybackRequestStage.PreAuth]: "text-yellow-600",
    [BuybackRequestStage.PostAuth]: "text-purple-600",
    [BuybackRequestStage.FinalOffer]: "text-orange-600",
    [BuybackRequestStage.OfferAccepted]: "text-green-600",
    [BuybackRequestStage.Rejected]: "text-red-600",
  };
  return stageColors[stage] || "text-gray-600";
};

