"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type {
  AcceptPreAuthOfferRequest,
  BuybackRequestFilters,
  RejectOfferRequest,
} from "../../types/buyback-request.types";
import { ApiKeys } from "../query-keys";
import {
  acceptPostAuthOffer,
  acceptPreAuthOffer,
  getActiveBuybacks,
  getBuybackRequestById,
  getBuybackRequests,
  getHistoricalBuybacks,
  rejectPostAuthOffer,
  rejectPreAuthOffer,
} from "../services/buyback-request.service";

export function useBuybackRequests(filters?: BuybackRequestFilters, enabled = true) {
  return useQuery({
    queryKey: ApiKeys.buybackRequests(filters),
    queryFn: () => getBuybackRequests(filters),
    enabled,
  });
}

export function useActiveBuybacks(
  params?: {
    search?: string;
    skip?: number;
    take?: number;
    order?: "ASC" | "DESC";
    categories?: string[];
    types?: string[];
  },
  enabled = true,
) {
  return useQuery({
    queryKey: ApiKeys.activeBuybacks(params),
    queryFn: () => getActiveBuybacks(params),
    enabled,
  });
}

export function useHistoricalBuybacks(params?: {
  search?: string;
  skip?: number;
  take?: number;
  order?: "ASC" | "DESC";
  categories?: string[];
  types?: string[];
}) {
  return useQuery({
    queryKey: ApiKeys.historicalBuybacks(params),
    queryFn: () => getHistoricalBuybacks(params),
  });
}

export function useBuybackRequest(id: string, enabled = true) {
  return useQuery({
    queryKey: ApiKeys.buybackRequests(id),
    queryFn: () => getBuybackRequestById(id),
    enabled,
  });
}

export function useAcceptPreAuthOffer() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({
      id,
      data,
    }: {
      id: string;
      data: AcceptPreAuthOfferRequest;
    }) => acceptPreAuthOffer(id, data),
    onSuccess: (_, { id }) => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests(id) });
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
    },
  });
}

export function useRejectPreAuthOffer() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ id, data }: { id: string; data: RejectOfferRequest }) =>
      rejectPreAuthOffer(id, data),
    onSuccess: (_, { id }) => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests(id) });
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
    },
  });
}

export function useAcceptPostAuthOffer() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => acceptPostAuthOffer(id),
    onSuccess: (_, id) => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests(id) });
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
    },
  });
}

export function useRejectPostAuthOffer() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ id, data }: { id: string; data: RejectOfferRequest }) =>
      rejectPostAuthOffer(id, data),
    onSuccess: (_, { id }) => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests(id) });
      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
    },
  });
}

