              <motion.p
                className="font-new-sans text-base text-white/70 min-[1172px]:text-lg"
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.5 }}
              >
                LuxFlow combines speed, security, and sophistication. With
                Brink&apos;s handling item custody and a multi-layered
                authentication process that combines AI and trusted experts.
              </motion.p>

              <motion.div
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.7 }}
              >
                {ctaHref ? (
                  <motion.div
                    whileHover={{ scale: 1.03 }}
                    whileTap={{ scale: 0.97 }}
                    className="w-fit"
                  >
                    <Link
                      href={ctaHref}
                      className="inline-flex h-12 items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-[#000E65]"
