"use client";

import {
  type Variants,
  motion,
  useScroll,
  useTransform,
} from "framer-motion";
import { CheckIcon, Lock, MessageSquare, ShieldCheck, Sparkles } from "lucide-react";
import { useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { useRef } from "react";

import { useRole } from "@/entities/auth/model/use-role";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getCdnUrl } from "@/shared/lib/utils/get-cdn-url";
import { useBuybackRequests } from "@/shared/api/query-hooks/use-buyback-requests";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/shared/ui/accordion";
import {
  getStatusLabel,
  type BuybackRequestListItem,
} from "@/shared/types/buyback-request.types";

import {
  LANDING_AUTH_FEATURES,
  LANDING_BRAND_LOGOS,
  LANDING_FAQ,
  LANDING_STEPS,
  LANDING_TRUST_FEATURES,
} from "../model/constants";

// ---------------------------------------------------------------------------
// Animation variants
// ---------------------------------------------------------------------------
const fadeUp: Variants = {
  hidden: { opacity: 0, y: 48 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
  },
};

const fadeIn: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { duration: 0.6, ease: "easeOut" },
  },
};

const slideLeft: Variants = {
  hidden: { opacity: 0, x: -60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const slideRight: Variants = {
  hidden: { opacity: 0, x: 60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const scaleIn: Variants = {
  hidden: { opacity: 0, scale: 0.88 },
  visible: {
    opacity: 1,
    scale: 1,
    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },
  },
};

const staggerContainer: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.1 } },
};

const staggerContainerSlow: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.15 } },
};

const VP = { once: true, margin: "-80px" };

// ---------------------------------------------------------------------------
// Value props — icons matching auth-layout.tsx
// ---------------------------------------------------------------------------
const VALUE_PROPS = [
  { id: "discreet", label: "100% Discreet", Icon: MessageSquare },
  { id: "ai", label: "AI Valuation", Icon: Sparkles },
  { id: "insured", label: "Fully-Insured", Icon: ShieldCheck },
  { id: "storage", label: "Secure Storage", Icon: Lock },
] as const;

// ---------------------------------------------------------------------------
// Gallery images
// ---------------------------------------------------------------------------
const GALLERY_IMAGES = [
  { src: "/new-design-images/landing-gallery/bags.jpg", alt: "Designer bags & accessories" },
  { src: "/new-design-images/landing-gallery/gold.jpg", alt: "Gold watches & precious metals" },
  { src: "/new-design-images/landing-gallery/jewerly-1.jpg", alt: "Fine jewelry & diamonds" },
] as const;

// ---------------------------------------------------------------------------
// Hero request card — shows the user's last buyback request
// ---------------------------------------------------------------------------
function HeroRequestCard({ request }: { request: BuybackRequestListItem }) {
  const { buyback } = request;
  const mainPhoto = buyback.asset.meta?.photos?.main ?? buyback.asset.photos?.[0];

  return (
    <Link
      href={APP_ROUTES.BUYBACK_REQUESTS.GET(request.id)}
      className="flex w-[300px] flex-col overflow-hidden rounded-2xl border border-white/20 bg-white/10 backdrop-blur-md transition-colors hover:bg-white/15"
    >
      {mainPhoto ? (
        <div className="relative h-48 w-full">
          <Image
            src={getCdnUrl(mainPhoto)}
            alt={buyback.asset.model?.name ?? "Luxury item"}
            fill
            className="object-cover"
            sizes="300px"
          />
        </div>
      ) : (
        <div className="flex h-48 w-full items-center justify-center bg-white/10">
          <Image
            src="/new-design-images/icons/watch-icon.svg"
            alt=""
            width={48}
            height={48}
            className="opacity-40"
          />
        </div>
      )}

      <div className="flex flex-col gap-1 p-4">
        <p className="font-medium font-new-sans text-sm text-white">
          {buyback.asset.brand?.name} {buyback.asset.model?.name}
        </p>
        <p className="font-new-sans text-xs text-white/50">
          {buyback.asset.category?.name}
        </p>
        <span className="mt-1 self-start rounded-full bg-white/20 px-2.5 py-0.5 font-new-sans text-[11px] text-white">
          {getStatusLabel(request.status)}
        </span>
      </div>
    </Link>
  );
}

// ---------------------------------------------------------------------------
// Hero headline — word-by-word reveal
// ---------------------------------------------------------------------------
function AnimatedHeadline({
  text,
  className,
}: {
  text: string;
  className?: string;
}) {
  const words = text.split(" ");
  return (
    <motion.h1
      className={className}
      variants={staggerContainer}
      initial="hidden"
      animate="visible"
    >
      {words.map((word, idx) => (
        <motion.span
          // eslint-disable-next-line react/no-array-index-key
          key={`word-${idx}`}
          className="inline-block"
          variants={{
            hidden: { opacity: 0, y: 40, rotateX: -15 },
            visible: {
              opacity: 1,
              y: 0,
              rotateX: 0,
              transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
            },
          }}
        >
          {word}
          {idx < words.length - 1 ? "\u00A0" : ""}
        </motion.span>
      ))}
    </motion.h1>
  );
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------
export function LandingPage() {
  const { status } = useSession();
  const { isSeller } = useRole();
  const isAuthenticated = status === "authenticated";

  const { data: requestsData } = useBuybackRequests(
    { take: 1, order: "DESC" },
    isAuthenticated,
  );
  const lastRequest = requestsData?.data?.[0];

  const ctaHref =
    isAuthenticated && !isSeller
      ? undefined
      : isAuthenticated
        ? APP_ROUTES.BUYBACK_REQUESTS.CREATE
        : `${APP_ROUTES.AUTH.SIGN_IN}?callbackUrl=${encodeURIComponent(APP_ROUTES.BUYBACK_REQUESTS.CREATE)}`;

  // Parallax for hero background
  const heroRef = useRef<HTMLElement>(null);
  const { scrollYProgress: heroScrollY } = useScroll({
    target: heroRef,
    offset: ["start start", "end start"],
  });
  const heroBgY = useTransform(heroScrollY, [0, 1], ["0%", "30%"]);

  return (
    <div className="new-design flex flex-col">
      {/* ================================================================
          1. HERO
      ================================================================ */}
      <section
        ref={heroRef}
        className="relative overflow-hidden bg-[#060B2F] px-6 pb-16 pt-20 min-[1172px]:px-16 min-[1172px]:pb-32 min-[1172px]:pt-36"
      >
        {/* Parallax background video */}
        <motion.div
          className="pointer-events-none absolute inset-0"
          style={{ y: heroBgY }}
        >
          <video
            autoPlay
            muted
            loop
            playsInline
            className="h-full w-full object-cover opacity-40"
            aria-hidden="true"
          >
            <source src="/new-design-videos/landing-hero-bg.mp4" type="video/mp4" />
          </video>
        </motion.div>
        <div className="pointer-events-none absolute inset-0 bg-gradient-to-b from-[#060B2F]/30 to-[#060B2F]/80" />

        <div className="relative mx-auto max-w-[1720px]">
          <div className="flex flex-col gap-10 min-[1172px]:flex-row min-[1172px]:items-end min-[1172px]:justify-between">
            <div className="flex max-w-2xl flex-col gap-6">
              {/* Word-by-word reveal */}
              <AnimatedHeadline
                text="Unlock instant liquidity"
                className="font-extralight font-new-serif text-5xl leading-[1.05] tracking-tight text-white [perspective:600px] min-[1172px]:text-[72px]"
              />

              <motion.p
                className="font-new-sans text-base text-white/70 min-[1172px]:text-lg"
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.5 }}
              >
                LuxFlow combines speed, security, and sophistication. With
                Brink&apos;s handling item custody and a multi-layered
                authentication process that combines AI and trusted experts.
              </motion.p>

              <motion.div
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.7 }}
              >
                {ctaHref ? (
                  <motion.div whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }} className="w-fit">
                    <Link
                      href={ctaHref}
                      className="inline-flex h-12 items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-[#000E65]"
                    >
                      Unlock Your Liquidity
                    </Link>
                  </motion.div>
                ) : (
                  <button
                    type="button"
                    disabled
                    className="inline-flex h-12 w-fit items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white opacity-50"
                  >
                    Unlock Your Liquidity
                  </button>
                )}
              </motion.div>
            </div>

            <motion.div
              className="flex flex-col items-start gap-1 text-white/50 min-[1172px]:items-end"
              variants={fadeIn}
              initial="hidden"
              animate="visible"
              transition={{ delay: 0.4 }}
            >
              <span className="font-new-sans text-sm">from your luxury items</span>
            </motion.div>
          </div>

          {/* Last request card — slides in from right if authenticated */}
          {isAuthenticated && lastRequest && (
            <motion.div
              className="absolute right-0 top-1/2 hidden -translate-y-1/2 min-[1172px]:block"
              variants={slideRight}
              initial="hidden"
              animate="visible"
              transition={{ delay: 0.3 }}
            >
              <HeroRequestCard request={lastRequest} />
            </motion.div>
          )}
        </div>
      </section>

      {/* ================================================================
          2. VALUE PROPOSITIONS
      ================================================================ */}
      <section className="bg-[#1236A8] px-6 py-14 min-[1172px]:px-16 min-[1172px]:py-20">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-12">
          <motion.p
            className="mx-auto max-w-2xl text-center font-new-sans text-base leading-relaxed text-white/80 min-[1172px]:text-lg"
            variants={fadeUp}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            LuxFlow combines speed, security, and sophistication. With
            Brink&apos;s handling item custody and a multi-layered
            authentication process that combines AI and trusted experts.
          </motion.p>

          <motion.div
            className="grid grid-cols-2 gap-4 min-[1172px]:grid-cols-4 min-[1172px]:gap-6"
            variants={staggerContainer}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {VALUE_PROPS.map(({ id, label, Icon }) => (
              <motion.div
                key={id}
                variants={scaleIn}
                whileHover={{ scale: 1.04, backgroundColor: "rgba(255,255,255,0.18)" }}
                className="flex flex-col items-center gap-4 rounded-2xl bg-white/10 px-4 py-6 text-center backdrop-blur-sm transition-colors"
              >
                <div className="flex h-12 w-12 items-center justify-center rounded-full bg-white/20">
                  <Icon size={24} className="text-white" strokeWidth={1.5} />
                </div>
                <span className="font-medium font-new-sans text-sm text-white">
                  {label}
                </span>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          3. GALLERY — "Liquid Luxury"
      ================================================================ */}
      <section className="bg-[#1236A8] px-6 pb-20 min-[1172px]:px-16">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-10">
          <motion.div
            className="grid grid-cols-1 gap-3 min-[768px]:grid-cols-3"
            variants={staggerContainer}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {GALLERY_IMAGES.map(({ src, alt }) => (
              <motion.div
                key={src}
                variants={fadeUp}
                className="relative overflow-hidden rounded-2xl"
                whileHover={{ scale: 1.02 }}
                transition={{ type: "spring", stiffness: 200, damping: 20 }}
              >
                <Image
                  src={src}
                  alt={alt}
                  width={560}
                  height={340}
                  className="h-[260px] w-full object-cover min-[1172px]:h-[340px]"
                  sizes="(min-width: 1172px) 33vw, 100vw"
                />
              </motion.div>
            ))}
          </motion.div>

          <div className="flex flex-col items-start gap-6 min-[1172px]:flex-row min-[1172px]:items-end min-[1172px]:justify-between">
            <motion.h2
              className="font-extralight font-new-serif text-4xl leading-[1.1] tracking-tight text-white min-[1172px]:text-[56px]"
              variants={fadeUp}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              Liquid Luxury
              <br />
              Fast. Discreet. Hassle-free.
            </motion.h2>

            {ctaHref ? (
              <motion.div
                variants={fadeIn}
                initial="hidden"
                whileInView="visible"
                viewport={VP}
                whileHover={{ scale: 1.03 }}
                whileTap={{ scale: 0.97 }}
                className="shrink-0"
              >
                <Link
                  href={ctaHref}
                  className="inline-flex h-12 items-center rounded-lg border border-white/30 bg-white/10 px-8 font-medium font-new-sans text-base text-white backdrop-blur-sm transition-colors hover:bg-white/20"
                >
                  Start with a Quote
                </Link>
              </motion.div>
            ) : null}
          </div>
        </div>
      </section>

      {/* ================================================================
          4. BUYBACK OPTIONS — two columns
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-16 min-[1172px]:px-16 min-[1172px]:py-24">
        <div className="mx-auto max-w-[1720px] grid grid-cols-1 gap-12 min-[1172px]:grid-cols-2 min-[1172px]:gap-16">
          {/* Left */}
          <motion.div
            className="flex flex-col gap-6"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <motion.div
              className="relative overflow-hidden rounded-2xl"
              whileHover={{ scale: 1.02 }}
              transition={{ type: "spring", stiffness: 200, damping: 20 }}
            >
              <Image
                src="/new-design-images/option/buyback.jpg"
                alt="Buyback option"
                width={640}
                height={320}
                className="h-[280px] w-full object-cover min-[1172px]:h-[320px]"
                sizes="(min-width: 1172px) 50vw, 100vw"
              />
            </motion.div>
            <div className="flex flex-col gap-3">
              <h3 className="font-extralight font-new-serif text-2xl leading-[1.2] text-[#44403C] min-[1172px]:text-3xl">
                Keep the option to
                <br />
                buy back your item
              </h3>
              <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                LuxFlow offers a flexible buyback option. Reclaim your luxury
                asset at the agreed price — no questions asked.
              </p>
              <Link
                href={APP_ROUTES.SERVICES.BUYBACK}
                className="font-medium font-new-sans text-sm text-[#021171] underline-offset-2 hover:underline"
              >
                Learn More
              </Link>
            </div>
          </motion.div>

          {/* Right */}
          <motion.div
            className="flex flex-col gap-6"
            variants={slideRight}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <motion.div
              className="relative overflow-hidden rounded-2xl"
              whileHover={{ scale: 1.02 }}
              transition={{ type: "spring", stiffness: 200, damping: 20 }}
            >
              <Image
                src="/new-design-images/option/direct-sale.jpg"
                alt="Direct sale option"
                width={640}
                height={320}
                className="h-[280px] w-full object-cover min-[1172px]:h-[320px]"
                sizes="(min-width: 1172px) 50vw, 100vw"
              />
            </motion.div>
            <div className="flex flex-col gap-3">
              <h3 className="font-extralight font-new-serif text-2xl leading-[1.2] text-[#44403C] min-[1172px]:text-3xl">
                Convert your items
                <br />
                into capital
              </h3>
              <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                Turn idle luxury assets into working capital instantly. LuxFlow
                connects you to a secure, fast, and discreet liquidity service.
              </p>
              <Link
                href={APP_ROUTES.SERVICES.DIRECT_SALE}
                className="font-medium font-new-sans text-sm text-[#021171] underline-offset-2 hover:underline"
              >
                Learn More
              </Link>
            </div>
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          5. STEPS — "Get Instant Cash in 4 Simple Steps"
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-16 min-[1172px]:px-16 min-[1172px]:py-24">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-12 min-[1172px]:flex-row min-[1172px]:items-start min-[1172px]:gap-20">
          {/* iPhone mockup */}
          <motion.div
            className="flex justify-center min-[1172px]:w-[380px] min-[1172px]:shrink-0 min-[1172px]:justify-start"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <Image
              src="/new-design-images/iphone-mockup.png"
              alt="LuxFlow mobile app"
              width={280}
              height={580}
              className="h-auto w-[240px] min-[1172px]:w-[280px]"
            />
          </motion.div>

          {/* Steps */}
          <div className="flex flex-1 flex-col gap-8">
            <motion.h2
              className="font-extralight font-new-serif text-3xl leading-[1.2] text-[#44403C] min-[1172px]:text-[44px]"
              variants={fadeUp}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              Get Instant Cash
              <br />
              in 4 Simple Steps
            </motion.h2>

            <motion.div
              className="flex flex-col gap-6"
              variants={staggerContainerSlow}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              {LANDING_STEPS.map((step) => (
                <motion.div
                  key={step.number}
                  className="flex items-start gap-4"
                  variants={fadeUp}
                >
                  <motion.div
                    className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-[#021171] font-medium font-new-sans text-sm text-white"
                    whileHover={{ scale: 1.15 }}
                  >
                    {step.number}
                  </motion.div>
                  <div className="flex flex-col gap-1">
                    <p className="font-medium font-new-sans text-sm text-[#44403C]">
                      {step.title}
                    </p>
                    <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                      {step.description}
                    </p>
                  </div>
                </motion.div>
              ))}
            </motion.div>

            {ctaHref ? (
              <motion.div
                variants={fadeUp}
                initial="hidden"
                whileInView="visible"
                viewport={VP}
                whileHover={{ scale: 1.03 }}
                whileTap={{ scale: 0.97 }}
                className="w-fit"
              >
                <Link
                  href={ctaHref}
                  className="inline-flex h-12 items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-[#000E65]"
                >
                  Contact Sales
                </Link>
              </motion.div>
            ) : null}
          </div>
        </div>
      </section>

      {/* ================================================================
          6. BRAND LOGOS — marquee with pause on hover
      ================================================================ */}
      <section className="overflow-hidden border-[#D6D3D1] border-y bg-[#F5F3EF] py-12">
        <div className="mx-auto max-w-[1720px] px-6 min-[1172px]:px-16">
          <motion.div
            className="mb-6 flex flex-col gap-1"
            variants={fadeUp}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <h2 className="font-extralight font-new-serif text-2xl text-[#44403C] min-[1172px]:text-3xl">
              Luxury Watches
            </h2>
            <p className="font-new-sans text-sm text-[#A8A29E]">
              An exclusive list of Exclusive Brands
            </p>
          </motion.div>
        </div>

        {/* Scrolling brand logos strip */}
        {/* Asset names: landing-brand-{brand-slug} — brand logo PNG/SVG files to add later */}
        <div className="flex overflow-hidden">
          <motion.div
            className="flex shrink-0 gap-12"
            animate={{ x: ["0%", "-50%"] }}
            transition={{ repeat: Infinity, duration: 30, ease: "linear" }}
            style={{ willChange: "transform" }}
          >
            {[...LANDING_BRAND_LOGOS, ...LANDING_BRAND_LOGOS].map(
              (brand, idx) => (
                <div
                  // eslint-disable-next-line react/no-array-index-key
                  key={`brand-${idx}`}
                  className="flex h-10 w-36 shrink-0 items-center justify-center"
                >
                  {/* Replace span with <Image> when brand logo assets are provided */}
                  {/* Asset name: /new-design-images/brands/{brand.toLowerCase().replace(/\s+/g, '-')}.svg */}
                  <span className="font-new-sans text-xs text-[#A8A29E]">
                    {brand}
                  </span>
                </div>
              ),
            )}
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          7. TESTIMONIAL / QUOTE
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-20 min-[1172px]:px-16 min-[1172px]:py-28">
        <motion.div
          className="mx-auto flex max-w-3xl flex-col items-center gap-8 text-center"
          variants={staggerContainer}
          initial="hidden"
          whileInView="visible"
          viewport={VP}
        >
          <motion.div
            className="flex h-16 w-16 items-center justify-center rounded-full bg-[#021171]"
            variants={scaleIn}
          >
            <Image
              src="/new-design-images/header-logo.svg"
              alt="LuxFlow"
              width={32}
              height={32}
              className="brightness-0 invert"
            />
          </motion.div>

          <motion.blockquote
            className="font-extralight font-new-serif text-2xl leading-[1.4] text-[#44403C] min-[1172px]:text-[32px]"
            variants={fadeUp}
          >
            &ldquo;LuxFlow is the elite liquidation platform for those who
            understand value. From secure storage by Brink&apos;s to verified
            authenticity checks, every item we handle undergoes a reputable
            handling process — trusted by sellers across the UAE and beyond.
            &rdquo;
          </motion.blockquote>
        </motion.div>
      </section>

      {/* ================================================================
          8. TRUST SECTION — blue wave background video
      ================================================================ */}
      <section className="relative overflow-hidden px-6 py-20 min-[1172px]:px-16 min-[1172px]:py-28">
        <video
          autoPlay
          muted
          loop
          playsInline
          className="pointer-events-none absolute inset-0 h-full w-full object-cover"
          aria-hidden="true"
        >
          <source src="/new-design-videos/bluebg.mp4" type="video/mp4" />
        </video>
        <div className="pointer-events-none absolute inset-0 bg-[#060B2F]/60" />

        <div className="relative mx-auto max-w-[1720px] grid grid-cols-1 gap-12 min-[1172px]:grid-cols-2 min-[1172px]:gap-20">
          <motion.div
            className="flex flex-col gap-8"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <p className="font-new-sans text-base leading-relaxed text-white/80 min-[1172px]:text-lg">
              From secure storage by Brink&apos;s to verified authenticity
              checks, every item we handle undergoes a reputable handling
              process of inspecting both sellers and their items.
            </p>
            {ctaHref ? (
              <motion.div whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }} className="w-fit">
                <Link
                  href={ctaHref}
                  className="inline-flex h-12 items-center rounded-lg border border-white/30 px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-white/10"
                >
                  Find out more
                </Link>
              </motion.div>
            ) : null}
          </motion.div>

          <motion.div
            className="flex flex-col gap-6"
            variants={staggerContainerSlow}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            {LANDING_TRUST_FEATURES.map((feature) => (
              <motion.div
                key={feature.title}
                className="flex items-start gap-4 border-white/10 border-b pb-6 last:border-b-0 last:pb-0"
                variants={slideRight}
              >
                <div className="mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-white/20">
                  <CheckIcon size={14} className="text-white" />
                </div>
                <div className="flex flex-col gap-1">
                  <p className="font-medium font-new-sans text-sm text-white">
                    {feature.title}
                  </p>
                  <p className="font-new-sans text-sm text-white/60">
                    {feature.description}
                  </p>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          9. CERTIFIED AUTHENTICATION
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 py-16 min-[1172px]:px-16 min-[1172px]:py-24">
        <div className="mx-auto max-w-[1720px] grid grid-cols-1 gap-12 min-[1172px]:grid-cols-2 min-[1172px]:gap-20">
          <motion.div
            className="flex flex-col gap-10"
            variants={slideLeft}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <h2 className="font-extralight font-new-serif text-3xl leading-[1.2] text-[#44403C] min-[1172px]:text-[44px]">
              Certified Authentication
              <br />
              &amp; Valuation with LuxFlow
            </h2>

            <motion.ul
              className="flex flex-col gap-0"
              variants={staggerContainerSlow}
              initial="hidden"
              whileInView="visible"
              viewport={VP}
            >
              {LANDING_AUTH_FEATURES.map((feature) => (
                <motion.li
                  key={feature}
                  className="flex items-center gap-4 border-[#D6D3D1] border-b py-4 last:border-b-0"
                  variants={fadeUp}
                >
                  <CheckIcon size={16} className="shrink-0 text-[#021171]" />
                  <span className="font-new-sans text-sm text-[#44403C]">
                    {feature}
                  </span>
                </motion.li>
              ))}
            </motion.ul>
          </motion.div>

          {/* Asset name: landing-authentication-image — person examining watch with white gloves */}
          {/* TODO: replace ImgPlaceholder with <Image> when asset is provided */}
          <motion.div
            className="flex items-center justify-center overflow-hidden rounded-2xl bg-[#C8C0B0]"
            variants={slideRight}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
            whileHover={{ scale: 1.02 }}
            transition={{ type: "spring", stiffness: 200, damping: 20 }}
          >
            <span className="px-4 py-8 text-center text-[10px] text-[#8A8070] min-[1172px]:py-0">
              landing-authentication-image
              <br />
              (expert examining luxury watch with white gloves)
            </span>
          </motion.div>
        </div>
      </section>

      {/* ================================================================
          10. FAQ
      ================================================================ */}
      <section className="bg-[#F5F3EF] px-6 pb-24 min-[1172px]:px-16">
        <div className="mx-auto max-w-[1720px]">
          <motion.div
            className="mb-10 border-[#D6D3D1] border-t pt-16"
            variants={fadeUp}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <h2 className="font-extralight font-new-serif text-3xl text-[#44403C] min-[1172px]:text-[44px]">
              Frequently Asked
              <br />
              Questions
            </h2>
          </motion.div>

          <motion.div
            variants={staggerContainerSlow}
            initial="hidden"
            whileInView="visible"
            viewport={VP}
          >
            <Accordion type="single" collapsible className="w-full max-w-3xl">
              {LANDING_FAQ.map((item, index) => (
                <motion.div
                  // eslint-disable-next-line react/no-array-index-key
                  key={`faq-${index}`}
                  variants={fadeUp}
                >
                  <AccordionItem value={`faq-${index}`}>
                    <AccordionTrigger className="font-extralight font-new-serif text-lg text-[#44403C] min-[1172px]:text-xl [&>span]:font-extralight [&>span]:font-new-serif">
                      {item.question}
                    </AccordionTrigger>
                    <AccordionContent>
                      <p className="font-new-sans text-sm leading-relaxed text-[#A8A29E]">
                        {item.answer}
                      </p>
                    </AccordionContent>
                  </AccordionItem>
                </motion.div>
              ))}
            </Accordion>
          </motion.div>
        </div>
      </section>
    </div>
  );
}

