"use client";

import {
  type Variants,
  motion,
  useScroll,
  useTransform,
} from "framer-motion";
import { CheckIcon, Lock, MessageSquare, ShieldCheck, Sparkles } from "lucide-react";
import { useSession } from "next-auth/react";
import Image from "next/image";
import Link from "next/link";
import { useRef } from "react";

import { useRole } from "@/entities/auth/model/use-role";
import { APP_ROUTES } from "@/shared/config/app-routes";
import { getCdnUrl } from "@/shared/lib/utils/get-cdn-url";
import { useBuybackRequests } from "@/shared/api/query-hooks/use-buyback-requests";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/shared/ui/accordion";
import {
  getStatusLabel,
  type BuybackRequestListItem,
} from "@/shared/types/buyback-request.types";

import {
  LANDING_AUTH_FEATURES,
  LANDING_BRAND_LOGOS,
  LANDING_FAQ,
  LANDING_STEPS,
  LANDING_TRUST_FEATURES,
} from "../model/constants";

// ---------------------------------------------------------------------------
// Animation variants
// ---------------------------------------------------------------------------
const fadeUp: Variants = {
  hidden: { opacity: 0, y: 48 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
  },
};

const fadeIn: Variants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { duration: 0.6, ease: "easeOut" },
  },
};

const slideLeft: Variants = {
  hidden: { opacity: 0, x: -60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const slideRight: Variants = {
  hidden: { opacity: 0, x: 60 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.8, ease: [0.22, 1, 0.36, 1] },
  },
};

const scaleIn: Variants = {
  hidden: { opacity: 0, scale: 0.88 },
  visible: {
    opacity: 1,
    scale: 1,
    transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] },
  },
};

const staggerContainer: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.1 } },
};

const staggerContainerSlow: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.15 } },
};

const VP = { once: true, margin: "-80px" };

// ---------------------------------------------------------------------------
// Value props — icons matching auth-layout.tsx
// ---------------------------------------------------------------------------
const VALUE_PROPS = [
  { id: "discreet", label: "100% Discreet", Icon: MessageSquare },
  { id: "ai", label: "AI Valuation", Icon: Sparkles },
  { id: "insured", label: "Fully-Insured", Icon: ShieldCheck },
  { id: "storage", label: "Secure Storage", Icon: Lock },
] as const;

// ---------------------------------------------------------------------------
// Gallery images
// ---------------------------------------------------------------------------
const GALLERY_IMAGES = [
  { src: "/new-design-images/landing-gallery/bags.jpg", alt: "Designer bags & accessories" },
  { src: "/new-design-images/landing-gallery/gold.jpg", alt: "Gold watches & precious metals" },
  { src: "/new-design-images/landing-gallery/jewerly-1.jpg", alt: "Fine jewelry & diamonds" },
] as const;

// ---------------------------------------------------------------------------
// Hero request card — shows the user's last buyback request
// ---------------------------------------------------------------------------
function HeroRequestCard({ request }: { request: BuybackRequestListItem }) {
  const { buyback } = request;
  const mainPhoto = buyback.asset.meta?.photos?.main ?? buyback.asset.photos?.[0];

  return (
    <Link
      href={APP_ROUTES.BUYBACK_REQUESTS.DETAIL(request.id)}
      className="flex w-[300px] flex-col overflow-hidden rounded-2xl border border-white/20 bg-white/10 backdrop-blur-md transition-colors hover:bg-white/15"
    >
      {mainPhoto ? (
        <div className="relative h-48 w-full">
          <Image
            src={getCdnUrl(mainPhoto)}
            alt={buyback.asset.model?.name ?? "Luxury item"}
            fill
            className="object-cover"
            sizes="300px"
          />
        </div>
      ) : (
        <div className="flex h-48 w-full items-center justify-center bg-white/10">
          <Image
            src="/new-design-images/icons/watch-icon.svg"
            alt=""
            width={48}
            height={48}
            className="opacity-40"
          />
        </div>
      )}

      <div className="flex flex-col gap-1 p-4">
        <p className="font-medium font-new-sans text-sm text-white">
          {buyback.asset.brand?.name} {buyback.asset.model?.name}
        </p>
        <p className="font-new-sans text-xs text-white/50">
          {buyback.asset.category?.name}
        </p>
        <span className="mt-1 self-start rounded-full bg-white/20 px-2.5 py-0.5 font-new-sans text-[11px] text-white">
          {getStatusLabel(request.status)}
        </span>
      </div>
    </Link>
  );
}

// ---------------------------------------------------------------------------
// Hero headline — word-by-word reveal
// ---------------------------------------------------------------------------
function AnimatedHeadline({
  text,
  className,
}: {
  text: string;
  className?: string;
}) {
  const words = text.split(" ");
  return (
    <motion.h1
      className={className}
      variants={staggerContainer}
      initial="hidden"
      animate="visible"
    >
      {words.map((word, idx) => (
        <motion.span
          // eslint-disable-next-line react/no-array-index-key
          key={`word-${idx}`}
          className="inline-block"
          variants={{
            hidden: { opacity: 0, y: 40, rotateX: -15 },
            visible: {
              opacity: 1,
              y: 0,
              rotateX: 0,
              transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
            },
          }}
        >
          {word}
          {idx < words.length - 1 ? "\u00A0" : ""}
        </motion.span>
      ))}
    </motion.h1>
  );
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------
export function LandingPage() {
  const { status } = useSession();
  const { isSeller } = useRole();
  const isAuthenticated = status === "authenticated";

  const { data: requestsData } = useBuybackRequests(
    { take: 1, order: "DESC" },
    isAuthenticated,
  );
  const lastRequest = requestsData?.data?.[0];

  const ctaHref =
    isAuthenticated && !isSeller
      ? undefined
      : isAuthenticated
        ? APP_ROUTES.BUYBACK_REQUESTS.CREATE
        : `${APP_ROUTES.AUTH.SIGN_IN}?callbackUrl=${encodeURIComponent(APP_ROUTES.BUYBACK_REQUESTS.CREATE)}`;

  // Parallax for hero background
  const heroRef = useRef<HTMLElement>(null);
  const { scrollYProgress: heroScrollY } = useScroll({
    target: heroRef,
    offset: ["start start", "end start"],
  });
  const heroBgY = useTransform(heroScrollY, [0, 1], ["0%", "30%"]);

  return (
    <div className="new-design flex flex-col">
      {/* ================================================================
          1. HERO
      ================================================================ */}
      <section
        ref={heroRef}
        className="relative overflow-hidden bg-[#060B2F] px-6 pb-16 pt-20 min-[1172px]:px-16 min-[1172px]:pb-32 min-[1172px]:pt-36"
      >
        {/* Parallax background video */}
        <motion.div
          className="pointer-events-none absolute inset-0"
          style={{ y: heroBgY }}
        >
          <video
            autoPlay
            muted
            loop
            playsInline
            className="h-full w-full object-cover opacity-40"
            aria-hidden="true"
          >
            <source src="/new-design-videos/landing-hero-bg.mp4" type="video/mp4" />
          </video>
        </motion.div>
        <div className="pointer-events-none absolute inset-0 bg-gradient-to-b from-[#060B2F]/30 to-[#060B2F]/80" />

        <div className="relative mx-auto max-w-[1720px]">
          <div className="flex flex-col gap-10 min-[1172px]:flex-row min-[1172px]:items-end min-[1172px]:justify-between">
            <div className="flex max-w-2xl flex-col gap-6">
              {/* Word-by-word reveal */}
              <AnimatedHeadline
                text="Unlock instant liquidity"
                className="font-extralight font-new-serif text-5xl leading-[1.05] tracking-tight text-white [perspective:600px] min-[1172px]:text-[72px]"
              />

              <motion.p
                className="font-new-sans text-base text-white/70 min-[1172px]:text-lg"
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.5 }}
              >
                LuxFlow combines speed, security, and sophistication. With
                Brink&apos;s handling item custody and a multi-layered
                authentication process that combines AI and trusted experts.
              </motion.p>

              <motion.div
                variants={fadeUp}
                initial="hidden"
                animate="visible"
                transition={{ delay: 0.7 }}
              >
                {ctaHref ? (
                  <motion.div whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }} className="w-fit">
                    <Link
                      href={ctaHref}
                      className="inline-flex h-12 items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white transition-colors hover:bg-[#000E65]"
                    >
                      Unlock Your Liquidity
                    </Link>
                  </motion.div>
                ) : (
                  <button
                    type="button"
                    disabled
                    className="inline-flex h-12 w-fit items-center rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-base text-white opacity-50"
                  >
                    Unlock Your Liquidity
                  </button>
                )}
              </motion.div>
            </div>

            <motion.div
              className="flex flex-col items-start gap-1 text-white/50 min-[1172px]:items-end"
              variants={fadeIn}
              initial="hidden"
              animate="visible"
              transition={{ delay: 0.4 }}
            >
              <span className="font-new-sans text-sm">from your luxury items</span>
            </motion.div>
          </div>

          {/* Last request card — slides in from right if authenticated */}
          {isAuthenticated && lastRequest && (
            <motion.div
              className="absolute right-0 top-1/2 hidden -translate-y-1/2 min-[1172px]:block"
              variants={slideRight}
              initial="hidden"
              animate="visible"
              transition={{ delay: 0.3 }}
            >
              <HeroRequestCard request={lastRequest} />
            </motion.div>
          )}
        </div>
      </section>

      {/* ================================================================
          2. VALUE PROPOSITIONS
      ================================================================ */}
      <section className="bg-[#1236A8] px-6 py-14 min-[1172px]:px-16 min-[1172px]:py-20">
        <div className="mx-auto flex max-w-[1720px] flex-col gap-12">
          <motion.p
            className="mx-auto max-w-2xl text-center font-new-sans text-base leading-relaxed text-white/80 min-[1172px]:text-lg"
            variants={fadeUp}
